<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Bouncing Ball Playground</title>
<style>
  html, body { height: 100%; }
  body {
    margin: 0;
    background: #0b0e14;
    color: #cfd8e3;
    font-family: ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  main {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 14px;
    padding: 20px;
  }
  h1 {
    margin: 0;
    font-size: 15px;
    font-weight: 600;
    letter-spacing: 0.14em;
    text-transform: uppercase;
    color: #8b98ab;
  }
  #controls { display: flex; gap: 10px; }
  button {
    background: #1c2330;
    color: #dbe2ec;
    border: 1px solid #2e3849;
    padding: 9px 20px;
    border-radius: 8px;
    font-size: 14px;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s ease, transform 0.05s ease;
  }
  button:hover { background: #263145; }
  button:active { transform: scale(0.96); }
  #sim {
    width: 640px;
    height: 480px;
    background: #10141c;
    border: 1px solid #262d3a;
    border-radius: 12px;
    box-shadow: 0 12px 44px rgba(0, 0, 0, 0.55);
    cursor: crosshair;
    touch-action: none;
  }
  .hint { margin: 0; font-size: 12px; color: #5c6778; }
</style>
</head>
<body>
<main>
  <h1>Bouncing Ball Playground</h1>
  <div id="controls">
    <button id="drop">Drop ball</button>
    <button id="play">Pause</button>
    <button id="clear">Clear</button>
  </div>
  <canvas id="sim" width="640" height="480"></canvas>
  <p class="hint">Click anywhere on the canvas to spawn a ball.</p>
</main>

<script>
(() => {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  const GRAVITY = 0.45;      // px per step^2
  const RESTITUTION = 0.82;  // energy kept on each bounce (< 1)
  const PALETTE = ['#ff6b6b', '#ffa94d', '#ffd43b', '#69db7c',
                   '#4dd4fa', '#748ffc', '#da77f2', '#f783ac'];

  const balls = [];
  let running = true;

  const rand = (a, b) => a + Math.random() * (b - a);
  const pick = arr => arr[Math.floor(Math.random() * arr.length)];

  function shade(hex, f) {
    const n = parseInt(hex.slice(1), 16);
    const r = Math.round(((n >> 16) & 255) * f);
    const g = Math.round(((n >> 8) & 255) * f);
    const b = Math.round((n & 255) * f);
    return `rgb(${r},${g},${b})`;
  }

  function addBall(x, y, vx = 0, vy = 0, r) {
    if (r == null || !isFinite(r) || r <= 0) r = rand(10, 20);
    r = Math.max(4, Math.min(r, Math.min(W, H) / 2));
    if (!isFinite(x)) x = W / 2;
    if (!isFinite(y)) y = H / 2;
    // spawn fully inside the canvas
    x = Math.min(Math.max(x, r), W - r);
    y = Math.min(Math.max(y, r), H - r);
    const b = { x, y, vx: vx || 0, vy: vy || 0, r, color: pick(PALETTE) };
    balls.push(b);
    return b;
  }

  function physics(dt) {
    for (const b of balls) {
      b.vy += GRAVITY * dt;          // gravity pulls down
      b.x += b.vx * dt;
      b.y += b.vy * dt;

      // walls: clamp inside + reverse perpendicular velocity (with energy loss)
      if (b.x < b.r)      { b.x = b.r;     b.vx =  Math.abs(b.vx) * RESTITUTION; }
      else if (b.x > W - b.r) { b.x = W - b.r; b.vx = -Math.abs(b.vx) * RESTITUTION; }

      // floor / ceiling
      if (b.y < b.r)      { b.y = b.r;     b.vy =  Math.abs(b.vy) * RESTITUTION; }
      else if (b.y > H - b.r) { b.y = H - b.r; b.vy = -Math.abs(b.vy) * RESTITUTION; }
    }
  }

  function draw() {
    ctx.fillStyle = '#10141c';
    ctx.fillRect(0, 0, W, H);

    // subtle grid
    ctx.strokeStyle = 'rgba(255,255,255,0.035)';
    ctx.lineWidth = 1;
    for (let gx = 40; gx < W; gx += 40) {
      ctx.beginPath(); ctx.moveTo(gx, 0); ctx.lineTo(gx, H); ctx.stroke();
    }
    for (let gy = 40; gy < H; gy += 40) {
      ctx.beginPath(); ctx.moveTo(0, gy); ctx.lineTo(W, gy); ctx.stroke();
    }

    for (const b of balls) {
      const g = ctx.createRadialGradient(
        b.x - b.r * 0.3, b.y - b.r * 0.35, b.r * 0.1,
        b.x, b.y, b.r
      );
      g.addColorStop(0, 'rgba(255,255,255,0.95)');
      g.addColorStop(0.3, b.color);
      g.addColorStop(1, shade(b.color, 0.45));
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = g;
      ctx.fill();
      ctx.strokeStyle = 'rgba(255,255,255,0.18)';
      ctx.lineWidth = 1;
      ctx.stroke();
    }
  }

  function frame() {
    if (running) physics(1);
    draw();
    requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);

  // ---- UI wiring -------------------------------------------------------
  const playBtn = document.getElementById('play');

  document.getElementById('drop').addEventListener('click', () => {
    addBall(rand(60, W - 60), rand(30, 80), rand(-3, 3), 0);
  });

  playBtn.addEventListener('click', () => {
    running = !running;
    playBtn.textContent = running ? 'Pause' : 'Play';
  });

  document.getElementById('clear').addEventListener('click', () => {
    balls.length = 0;
  });

  canvas.addEventListener('pointerdown', (e) => {
    const rect = canvas.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (W / rect.width);
    const y = (e.clientY - rect.top) * (H / rect.height);
    addBall(x, y, rand(-2.5, 2.5), rand(-1, 0));
  });

  // ---- programmatic grading API ----------------------------------------
  window.sim = {
    w: W,
    h: H,
    balls() { return balls.slice(); }, // live ball objects: {x, y, vx, vy, r, ...}
    addBall(x, y, vx = 0, vy = 0, r) { return addBall(x, y, vx, vy, r); },
    clear() { balls.length = 0; draw(); },
    step(dt = 1) { physics(dt); draw(); },
  };

  draw();
})();
</script>
</body>
</html>
